1	/** A live cell's coordinates as [x, y]. */
2	export type Cell = [number, number];
3	
4	/**
5	 * Returns the next generation of live cells per Conway's Game of Life rules.
6	 *
7	 * Rules:
8	 *  - Underpopulation: a live cell with fewer than 2 live neighbors dies.
9	 *  - Survival: a live cell with 2 or 3 live neighbors lives on.
10	 *  - Overpopulation: a live cell with more than 3 live neighbors dies.
11	 *  - Reproduction: a dead cell with exactly 3 live neighbors becomes alive.
12	 */
13	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
14	  [-1, -1], [-1, 0], [-1, 1],
15	  [ 0, -1],          [ 0, 1],
16	  [ 1, -1], [ 1, 0], [ 1, 1],
17	];
18	
19	const toKey = ([x, y]: Cell): string => `${x},${y}`;
20	
21	export function nextGeneration(liveCells: Cell[]): Cell[] {
22	  const liveSet = new Set(liveCells.map(toKey));
23	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
24	
25	  for (const [x, y] of liveCells) {
26	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
27	      const neighbor: Cell = [x + dx, y + dy];
28	      const key = toKey(neighbor);
29	      const entry = neighborCounts.get(key);
30	      if (entry) entry.count++;
31	      else neighborCounts.set(key, { cell: neighbor, count: 1 });
32	    }
33	  }
34	
35	  const survivors: Cell[] = [];
36	  for (const { cell, count } of neighborCounts.values()) {
37	    const alive = liveSet.has(toKey(cell));
38	    if (count === 3 || (alive && count === 2)) survivors.push(cell);
39	  }
40	  return survivors;
41	}
42

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty input returns empty array — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation, 0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with 2 neighbors survives (Rule 2 - Survival) — blinker center stays alive", () => {
15	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
16	    expect(result).toContainEqual([0, 1]);
17	  });
18	  it("live cell with 4 neighbors dies (Rule 3 - Overpopulation) — center of '###/.#./###' dies", () => {
19	    const result = nextGeneration([
20	      [0, 0], [1, 0], [2, 0],
21	      [1, 1],
22	      [0, 2], [1, 2], [2, 2],
23	    ]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("dead cell with exactly 3 neighbors becomes alive (Rule 4 - Reproduction) — '##./#../...' → '##./##./...'", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
31	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
32	    const result = nextGeneration(block);
33	    expect(result).toHaveLength(4);
34	    for (const cell of block) {
35	      expect(result).toContainEqual(cell);
36	    }
37	  });
38	  it("blinker oscillator vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
39	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
40	    expect(result).toHaveLength(3);
41	    expect(result).toContainEqual([-1, 1]);
42	    expect(result).toContainEqual([0, 1]);
43	    expect(result).toContainEqual([1, 1]);
44	  });
45	  it.todo("handles negative coordinates correctly");
46	});
