const toKey = ([x, y]: Cell): string => `${x},${y}`;

const isAliveNextGeneration = (isCurrentlyAlive: boolean, liveNeighborCount: number): boolean =>
  liveNeighborCount === 3 || (isCurrentlyAlive && liveNeighborCount === 2);

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(toKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = toKey(neighbor);
      const entry = neighborCounts.get(key);
      if (entry) entry.count++;
      else neighborCounts.set(key, { cell: neighbor, count: 1 });
    }
  }

  const nextLiveCells: Cell[] = [];
  for (const { cell, count } of neighborCounts.values()) {
    if (isAliveNextGeneration(liveSet.has(toKey(cell)), count)) {
      nextLiveCells.push(cell);
    }
  }
  return nextLiveCells;
}
